import ast, pathlib

for pyfile in pathlib.Path('myproject').glob('*.py'):
    tree = ast.parse(pyfile.read_text())
    for node in ast.walk(tree):
        # Check for ReactQuill class inheriting from NoSSRComponent
        if isinstance(node, ast.ClassDef) and node.name == 'ReactQuill':
            print(f'Found class ReactQuill in {pyfile}')
            bases = [ast.unparse(b) for b in node.bases]
            print(f'  Bases: {bases}')
            for item in node.body:
                if isinstance(item, ast.Assign):
                    for target in item.targets:
                        if isinstance(target, ast.Name):
                            print(f'  Class attr: {target.id} = {ast.unparse(item.value)}')
                elif isinstance(item, ast.AnnAssign) and isinstance(item.target, ast.Name):
                    print(f'  Class attr: {item.target.id}: {ast.unparse(item.annotation)}')
        # Check for State class
        if isinstance(node, ast.ClassDef) and 'State' in node.name:
            bases = [ast.unparse(b) for b in node.bases]
            if any('State' in b for b in bases):
                print(f'Found State class {node.name} in {pyfile}')
                for item in node.body:
                    if isinstance(item, ast.AnnAssign) and isinstance(item.target, ast.Name):
                        val = ast.unparse(item.value) if item.value else 'N/A'
                        print(f'  State var: {item.target.id}: {ast.unparse(item.annotation)} = {val}')
                    elif isinstance(item, ast.FunctionDef):
                        print(f'  State handler: {item.name}({ast.unparse(item.args)})')
        # Check for module-level react_quill assignment
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == 'react_quill':
                    print(f'Found react_quill factory in {pyfile}: {ast.unparse(node.value)}')
